import React, { useState } from 'react';
import { authService } from '../services/api';

function Login({ onLogin, tabId }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showRegister, setShowRegister] = useState(false);

  const [registerData, setRegisterData] = useState({
    fullName: '',
    email: '',
    password: '',
    confirmPassword: '',
    userRole: 'Partner',
    phoneNumber: '',
    companyName: '',
    address: ''
  });

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await authService.login(email, password);
      onLogin(response);
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password');
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError('');

    if (registerData.password !== registerData.confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    if (registerData.password.length < 6) {
      setError('Password must be at least 6 characters');
      return;
    }

    setLoading(true);

    try {
      const { confirmPassword, ...dataToSend } = registerData;
      const response = await authService.register(dataToSend);
      onLogin(response);
    } catch (err) {
      setError(
        err.response?.data?.message ||
        err.response?.data?.title ||
        'Registration failed'
      );
    } finally {
      setLoading(false);
    }
  };

  const toggleForm = () => {
    setShowRegister(!showRegister);
    setError('');
    setEmail('');
    setPassword('');
    setRegisterData({
      fullName: '',
      email: '',
      password: '',
      confirmPassword: '',
      userRole: 'Partner',
      phoneNumber: '',
      companyName: '',
      address: ''
    });
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '1rem'
    }}>
      <div style={{
        background: 'white',
        padding: '2rem',
        borderRadius: '10px',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
        width: '100%',
        maxWidth: showRegister ? '600px' : '450px',
        maxHeight: '90vh',
        overflowY: 'auto'
      }}>
        <h1 style={{ textAlign: 'center', color: '#667eea', marginBottom: '0.5rem' }}>
          Sales ERP
        </h1>

        <p style={{ textAlign: 'center', color: '#666', marginBottom: '0.5rem' }}>
          {showRegister ? 'Create your account' : 'Login to your account'}
        </p>

        {/* TAB ID DISPLAY */}
        {tabId && (
          <p style={{
            textAlign: 'center',
            fontSize: '0.7rem',
            color: '#999',
            fontFamily: 'monospace',
            marginBottom: '1rem',
            padding: '0.5rem',
            background: '#f5f5f5',
            borderRadius: '4px'
          }}>
            Tab ID: {tabId.substring(0, 20)}...
          </p>
        )}

        {error && (
          <div style={{
            background: '#fee',
            border: '1px solid #fcc',
            color: '#c33',
            padding: '0.75rem',
            borderRadius: '5px',
            marginBottom: '1rem'
          }}>
            {error}
          </div>
        )}

        {!showRegister ? (
          <form onSubmit={handleLogin}>
            <input
              type="email"
              placeholder="Email"
              value={email}
              disabled={loading}
              onChange={(e) => setEmail(e.target.value)}
              required
              style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem' }}
            />

            <input
              type="password"
              placeholder="Password"
              value={password}
              disabled={loading}
              onChange={(e) => setPassword(e.target.value)}
              required
              style={{ width: '100%', padding: '0.75rem', marginBottom: '1.5rem' }}
            />

            <button
              type="submit"
              disabled={loading}
              style={{
                width: '100%',
                padding: '0.75rem',
                background: '#667eea',
                color: 'white',
                border: 'none',
                borderRadius: '5px'
              }}
            >
              {loading ? 'Logging in...' : 'Login'}
            </button>

            <p style={{ textAlign: 'center', marginTop: '1rem' }}>
              Don’t have an account?{' '}
              <button type="button" onClick={toggleForm} style={{ border: 'none', background: 'none', color: '#667eea' }}>
                Register
              </button>
            </p>
          </form>
        ) : (
          <form onSubmit={handleRegister}>
            <input
              placeholder="Full Name"
              value={registerData.fullName}
              onChange={(e) => setRegisterData({ ...registerData, fullName: e.target.value })}
              required
              style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem' }}
            />

            <input
              placeholder="Email"
              type="email"
              value={registerData.email}
              onChange={(e) => setRegisterData({ ...registerData, email: e.target.value })}
              required
              style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem' }}
            />

            <input
              placeholder="Password"
              type="password"
              value={registerData.password}
              onChange={(e) => setRegisterData({ ...registerData, password: e.target.value })}
              required
              style={{ width: '100%', padding: '0.75rem', marginBottom: '1rem' }}
            />

            <input
              placeholder="Confirm Password"
              type="password"
              value={registerData.confirmPassword}
              onChange={(e) => setRegisterData({ ...registerData, confirmPassword: e.target.value })}
              required
              style={{ width: '100%', padding: '0.75rem', marginBottom: '1.5rem' }}
            />

            <button
              type="submit"
              disabled={loading}
              style={{
                width: '100%',
                padding: '0.75rem',
                background: '#667eea',
                color: 'white',
                border: 'none',
                borderRadius: '5px'
              }}
            >
              {loading ? 'Creating account...' : 'Register'}
            </button>

            <p style={{ textAlign: 'center', marginTop: '1rem' }}>
              Already have an account?{' '}
              <button type="button" onClick={toggleForm} style={{ border: 'none', background: 'none', color: '#667eea' }}>
                Login
              </button>
            </p>
          </form>
        )}
      </div>
    </div>
  );
}

export default Login;
